26	const PROCESSING_FEE = 5;
27	const FIRST_INSURANCE_RATE = 0.1;
28	
29	const BASE_PREMIUM: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	};
35	
36	const premiumForItem = (item: Item): number => {
37	  const base = BASE_PREMIUM[item.type];
38	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
39	  return base + firstInsuranceSurcharge;
40	};
