42	export const quote = (
43	  _customer: Customer,
44	  items: Item[],
45	  _priorContracts: number,
46	): number => {
47	  const itemsTotal = items.reduce((sum, item) => sum + premiumForItem(item), 0);
48	  return itemsTotal + PROCESSING_FEE;
49	};
