1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, [], 0)).toBe(5);
8	  });
9	
10	  // Base premiums per item type (newcomer, no modifiers beyond first insurance & fee)
11	  it("single plain sword for newcomer (no prior contracts) → base 100 + 10 first + 5 fee = 115 G", () => {
12	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 0)).toBe(115);
13	  });
14	  it("single plain amulet for newcomer → base 60 + 6 first + 5 fee = 71 G", () => {
15	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 0)).toBe(71);
16	  });
17	  it("single plain staff for newcomer → base 80 + 8 first + 5 fee = 93 G", () => {
18	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }], 0)).toBe(93);
19	  });
20	  it("single plain potion for newcomer → base 40 + 4 first + 5 fee = 49 G", () => {
21	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }], 0)).toBe(49);
22	  });
23	
24	  // Components — base premiums (newcomer; verifying base before block rule)
25	  it.todo("2 runes → base 50 G (no block; +5 first +5 fee = 60 G)");
26	  it.todo("3 runes → base 60 G via block (+6 first +5 fee = 71 G)");
27	  it.todo("4 runes → base 100 G (no block; block requires exactly 3) → +10 first +5 fee = 115 G");
28	  it.todo("7 runes → base 175 G");
29	
30	  // "Alike" components clarification
31	  it.todo("2 runes + 1 moonstone → base 75 G (no block — different types)");
32	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
33	
34	  // Item-specific modifiers
35	  it.todo("cursed sword for newcomer → 100 + 50 curse + 10 first + 5 fee = 165 G");
36	  it.todo("sword with enchantment exactly 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G");
37	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115 G");
38	  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges apply");
39	
40	  // Modifier scope on multi-item policies (clarifying question ❓)
41	  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (newcomer additions extra)");
42	
43	  // Loyalty discount threshold
44	  it.todo("customer with exactly 2 years → loyalty discount applies (20% of policy base)");
45	  it.todo("customer with 1 year → no loyalty discount");
46	
47	  // Follow-up contract discount (each contract after the first → 15% off policy base)
48	  it.todo("second contract for same customer in same scenario → 15% follow-up discount applies");
49	
50	  // First insurance per item, regardless of customer history (❓ clarification)
51	  it.todo("long-standing customer's second contract: cursed sword ench 7 → premium 160 G (matches spec integration example)");
52	
53	  // Rounding in MHPCO's favor
54	  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");
55	
56	  // Errors
57	  it.todo("unknown item type in quote → throws error");
58	});
