60	describe("MHPCO Claim Office — claim", () => {
61	  // Standard reimbursement (no special clauses)
62	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
63	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
64	
65	  // Enchantment ≥8 clause
66	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
67	
68	  // Dragon material clause
69	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
70	
71	  // Both clauses — 50% wins, then deductible
72	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
73	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
74	
75	  // Deductible per damage event
76	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
77	
78	  // Multiple items of same type
79	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
80	  it.todo("damages array has more entries of a type than the policy covers → throws error");
