82	  // Cap exhaustion
83	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
84	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
85	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
86	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
87	
88	  // Rounding for payouts
89	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
90	
91	  // Errors
